sections.code_example:
age = 20
has_ticket = True

if age >= 18:
    print("Age check passed.")
    if has_ticket:
        print("Welcome to the event!")
    else:
        print("You need a ticket.")
else:
    print("Sorry, you must be 18 or older.")

# Nested approach — tells you WHICH check failed
age = 17
has_ticket = True

if age >= 18:
    if has_ticket:
        print("Welcome!")
    else:
        print("Need a ticket.")
else:
    print("Must be 18+.")

# Simplified with 'and' — same pass/fail, shorter code
if age >= 18 and has_ticket:
    print("Welcome!")
else:
    print("Entry denied.")

